import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"朝阳公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/chaoyang-park.md","filePath":"parks/chaoyang-park.md","lastUpdated":null}'),n={name:"parks/chaoyang-park.md"};function d(o,t,i,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="朝阳公园" tabindex="-1">朝阳公园 <a class="header-anchor" href="#朝阳公园" aria-label="Permalink to &quot;朝阳公园&quot;">​</a></h1><blockquote><p>&quot;四环内最大的城市公园，音乐节的举办地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>朝阳公园位于北京市朝阳区，是北京市四环内最大的城市公园。公园占地约290公顷，其中水面约68公顷，是北京市民休闲娱乐的重要场所。朝阳公园也是北京著名的音乐节举办地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:00-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁14号线朝阳公园站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区朝阳公园南路1号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="水碓公园" tabindex="-1">水碓公园 <a class="header-anchor" href="#水碓公园" aria-label="Permalink to &quot;水碓公园&quot;">​</a></h3><p>朝阳公园前身是水碓公园，1984年开始建设，1987年建成开放。</p><h3 id="改名朝阳公园" tabindex="-1">改名朝阳公园 <a class="header-anchor" href="#改名朝阳公园" aria-label="Permalink to &quot;改名朝阳公园&quot;">​</a></h3><p>1992年，水碓公园改名&quot;朝阳公园&quot;，并进行大规模扩建。</p><h3 id="现代发展" tabindex="-1">现代发展 <a class="header-anchor" href="#现代发展" aria-label="Permalink to &quot;现代发展&quot;">​</a></h3><p>2000年后，朝阳公园不断完善设施，增加游乐项目，成为北京市民喜爱的城市公园。</p><h2 id="园区布局" tabindex="-1">园区布局 <a class="header-anchor" href="#园区布局" aria-label="Permalink to &quot;园区布局&quot;">​</a></h2><p>朝阳公园分为多个景区。</p><h3 id="中心岛" tabindex="-1">中心岛 <a class="header-anchor" href="#中心岛" aria-label="Permalink to &quot;中心岛&quot;">​</a></h3><p>中心岛是公园的核心景区，有万人广场、世纪喷泉等。</p><h4 id="万人广场" tabindex="-1">万人广场 <a class="header-anchor" href="#万人广场" aria-label="Permalink to &quot;万人广场&quot;">​</a></h4><p>万人广场是朝阳公园最大的广场，可容纳数万人。这里是音乐节的主要举办地。</p><h4 id="世纪喷泉" tabindex="-1">世纪喷泉 <a class="header-anchor" href="#世纪喷泉" aria-label="Permalink to &quot;世纪喷泉&quot;">​</a></h4><p>世纪喷泉是朝阳公园的标志性景观，喷泉水柱最高可达数十米。</p><h3 id="沙滩排球场" tabindex="-1">沙滩排球场 <a class="header-anchor" href="#沙滩排球场" aria-label="Permalink to &quot;沙滩排球场&quot;">​</a></h3><p>沙滩排球场是北京沙滩排球的训练基地，有专业的沙滩排球场。</p><h3 id="游乐园" tabindex="-1">游乐园 <a class="header-anchor" href="#游乐园" aria-label="Permalink to &quot;游乐园&quot;">​</a></h3><p>公园内有游乐园，有各种游乐设施。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>过山车</strong></td><td style="text-align:left;">刺激的过山车</td></tr><tr><td style="text-align:left;"><strong>旋转木马</strong></td><td style="text-align:left;">经典的旋转木马</td></tr><tr><td style="text-align:left;"><strong>碰碰车</strong></td><td style="text-align:left;">好玩的碰碰车</td></tr><tr><td style="text-align:left;"><strong>摩天轮</strong></td><td style="text-align:left;">浪漫的摩天轮</td></tr></tbody></table><h3 id="水上游乐" tabindex="-1">水上游乐 <a class="header-anchor" href="#水上游乐" aria-label="Permalink to &quot;水上游乐&quot;">​</a></h3><p>公园内有大片水面，可以划船、脚踏船等。</p><h2 id="音乐节" tabindex="-1">音乐节 <a class="header-anchor" href="#音乐节" aria-label="Permalink to &quot;音乐节&quot;">​</a></h2><p>朝阳公园是北京著名的音乐节举办地。</p><h3 id="草莓音乐节" tabindex="-1">草莓音乐节 <a class="header-anchor" href="#草莓音乐节" aria-label="Permalink to &quot;草莓音乐节&quot;">​</a></h3><p>草莓音乐节是国内著名的音乐节品牌，每年在朝阳公园举办。</p><h4 id="举办时间" tabindex="-1">举办时间 <a class="header-anchor" href="#举办时间" aria-label="Permalink to &quot;举办时间&quot;">​</a></h4><p>每年5月左右，具体时间以官方公告为准。</p><h4 id="参演艺人" tabindex="-1">参演艺人 <a class="header-anchor" href="#参演艺人" aria-label="Permalink to &quot;参演艺人&quot;">​</a></h4><p>邀请国内外知名乐队和歌手参演。</p><h3 id="其他音乐节" tabindex="-1">其他音乐节 <a class="header-anchor" href="#其他音乐节" aria-label="Permalink to &quot;其他音乐节&quot;">​</a></h3><p>朝阳公园还举办其他各种音乐节和演出活动。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>南门 → 万人广场 → 世纪喷泉 → 游乐园 → 沙滩排球场 → 水上游乐 → 北门</p><p><strong>音乐节路线</strong>：</p><p>万人广场 → 舞台区 → 美食区 → 休息区</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">14号线朝阳公园站B口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">302路、350路、406路等朝阳公园桥西站</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">公园有停车场</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费入园</strong>：公园免费开放</li><li><strong>音乐节抢票</strong>：音乐节票源紧张，需提前抢票</li><li><strong>避开高峰</strong>：周末人较多，建议工作日</li><li><strong>游乐项目</strong>：游乐园需另外购票</li><li><strong>划船体验</strong>：可以划船游湖</li><li><strong>夜间活动</strong>：夜间有灯光秀等活动</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">蓝色港湾</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">商业区</td></tr><tr><td style="text-align:left;">三里屯</td><td style="text-align:center;">地铁1站</td><td style="text-align:left;">时尚商业区</td></tr><tr><td style="text-align:left;">国贸</td><td style="text-align:center;">地铁2站</td><td style="text-align:left;">商务中心</td></tr><tr><td style="text-align:left;">朝阳大悦城</td><td style="text-align:center;">地铁2站</td><td style="text-align:left;">大型商场</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市朝阳区朝阳公园南路1号 <strong>📞 电话</strong>：010-65953490</p>',52)])])}const c=a(n,[["render",d]]);export{f as __pageData,c as default};
